10	func writeExecResult(t *testing.T, execRoot, sessionID string, payload map[string]any) {
11		t.Helper()
12	
13		dir := filepath.Join(execRoot, sessionID)
14		if err := os.MkdirAll(dir, 0o755); err != nil {
15			t.Fatalf("mkdir exec result dir: %v", err)
16		}
17		raw, err := json.Marshal(payload)
18		if err != nil {
19			t.Fatalf("marshal exec result: %v", err)
20		}
21		if err := os.WriteFile(filepath.Join(dir, "result.json"), raw, 0o644); err != nil {
22			t.Fatalf("write exec result: %v", err)
23		}
24	}
