342	// githubTarballURL builds a GitHub release tarball URL from a repo URL and version tag.
343	// e.g. "https://github.com/owner/repo" + "1.0.0" →
344	//
345	//	"https://github.com/owner/repo/archive/refs/tags/v1.0.0.tar.gz"
346	func githubTarballURL(repoURL, version string) string {
347		tag := version
348		if !strings.HasPrefix(tag, "v") {
349			tag = "v" + tag
350		}
351		return strings.TrimRight(repoURL, "/") + "/archive/refs/tags/" + tag + ".tar.gz"
