604	// ExpandHome expands a leading ~ to the user's home directory.
605	func ExpandHome(path string) string {
606		if !strings.HasPrefix(path, "~") {
607			return path
608		}
609		home, err := os.UserHomeDir()
610		if err != nil {
611			return path
612		}
613		return filepath.Join(home, path[1:])
614	}
